('M021', 'If g(x) = x/2 + 7, what is g(10)?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'algebra'), (SELECT id FROM skills WHERE id = 'a8888888-8888-8888-8888-888888888888'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "10"}, {"label": "B", "text": "12"}, {"label": "C", "text": "14"}, {"label": "D", "text": "17"}]'::jsonb, 'B', 'Substitute x = 10: 10/2 + 7 = 5 + 7 = 12.', ARRAY['sat', 'math', 'algebra', 'function_evaluation'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('M022', 'A car travels 180 miles in 3 hours at a constant speed. How many miles does it travel in 5 hours?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'algebra'), (SELECT id FROM skills WHERE id = 'a2222222-2222-2222-2222-222222222222'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "270"}, {"label": "B", "text": "300"}, {"label": "C", "text": "280"}, {"label": "D", "text": "320"}]'::jsonb, 'B', 'The speed is 60 mph, so 5 hours × 60 = 300 miles.', ARRAY['sat', 'math', 'algebra', 'unit_rate'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('M023', 'If 3x = 2y and y = 12, what is x?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'algebra'), (SELECT id FROM skills WHERE id = 'a9999999-9999-9999-9999-999999999999'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "6"}, {"label": "B", "text": "8"}, {"label": "C", "text": "10"}, {"label": "D", "text": "12"}]'::jsonb, 'B', 'Substitute y = 12: 3x = 24, so x = 8.', ARRAY['sat', 'math', 'algebra', 'solving_equations'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('M024', 'What is the value of 2^3 × 2^4?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'advanced-math'), (SELECT id FROM skills WHERE id = 'b4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "64"}, {"label": "B", "text": "128"}, {"label": "C", "text": "256"}, {"label": "D", "text": "32"}]'::jsonb, 'B', 'When multiplying powers with the same base, add exponents: 2^7 = 128.', ARRAY['sat', 'math', 'advanced_math', 'exponents'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('M025', 'If the line y = 3x + 1 crosses the y-axis, what is the y-intercept?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'algebra'), (SELECT id FROM skills WHERE id = '2bd9578b-1a5d-47d3-8ee3-ed8937992e7c'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "3"}, {"label": "B", "text": "1"}, {"label": "C", "text": "-1"}, {"label": "D", "text": "0"}]'::jsonb, 'B', 'In slope-intercept form, the y-intercept is the constant term 1.', ARRAY['sat', 'math', 'algebra', 'linear_functions'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('M026', 'A data set has values 2, 4, 6, 8, and 20. Which measure is most affected by the 20?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'problem-solving-data'), (SELECT id FROM skills WHERE id = 'd3333333-3333-3333-3333-333333333333'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "median"}, {"label": "B", "text": "mean"}, {"label": "C", "text": "range"}, {"label": "D", "text": "mode"}]'::jsonb, 'B', 'The mean changes more than the median when an outlier is present.', ARRAY['sat', 'math', 'statistics', 'interpreting_data'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('M027', 'Which expression is equivalent to 5(x + 4) - 2x?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'algebra'), (SELECT id FROM skills WHERE id = 'a5555555-5555-5555-5555-555555555555'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "7x + 20"}, {"label": "B", "text": "3x + 20"}, {"label": "C", "text": "3x + 4"}, {"label": "D", "text": "5x + 8"}]'::jsonb, 'B', 'Distribute the 5 to get 5x + 20, then subtract 2x to get 3x + 20.', ARRAY['sat', 'math', 'algebra', 'expression_simplification'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('M028', 'A 12-ounce smoothie costs $4.80. What is the cost per ounce?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'algebra'), (SELECT id FROM skills WHERE id = 'a2222222-2222-2222-2222-222222222222'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "0.3"}, {"label": "B", "text": "0.4"}, {"label": "C", "text": "0.5"}, {"label": "D", "text": "0.6"}]'::jsonb, 'B', 'Divide 4.80 by 12 to get 0.40 per ounce.', ARRAY['sat', 'math', 'algebra', 'unit_rate'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('M029', 'What is the value of x in the equation 7x + 3 = 31?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'algebra'), (SELECT id FROM skills WHERE id = '5b31574d-b72a-4b5d-ae15-81b144cff4ec'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "3"}, {"label": "B", "text": "4"}, {"label": "C", "text": "5"}, {"label": "D", "text": "6"}]'::jsonb, 'B', 'Subtract 3 to get 7x = 28, then divide by 7.', ARRAY['sat', 'math', 'algebra', 'linear_equations'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('M030', 'A garden is 9 feet by 14 feet. What is its area?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'geometry-trigonometry'), (SELECT id FROM skills WHERE id = 'c3333333-3333-3333-3333-333333333333'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "46"}, {"label": "B", "text": "126"}, {"label": "C", "text": "112"}, {"label": "D", "text": "134"}]'::jsonb, 'B', 'Area = length × width = 9 × 14 = 126.', ARRAY['sat', 'math', 'geometry', 'area_of_rectangles'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status);

-- M031-M039
INSERT INTO question_bank (display_id, question_text, section, domain_id, skill_id, difficulty, question_format, choices, correct_answer, explanation, tags, gamemodes, source, status) VALUES
('M031', 'If the points (1, 2) and (1, 9) are on a graph, what is true about the line?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'algebra'), (SELECT id FROM skills WHERE id = 'a0a0a0a0-a0a0-a0a0-a0a0-a0a0a0a0a0a0'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "It has slope 0."}, {"label": "B", "text": "It is vertical."}, {"label": "C", "text": "It is horizontal."}, {"label": "D", "text": "Its slope is 1."}]'::jsonb, 'B', 'Both points have the same x-value, so the line is vertical.', ARRAY['sat', 'math', 'algebra', 'graph_interpretation'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('M032', 'What is the result of 18 ÷ 3 + 4?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'algebra'), (SELECT id FROM skills WHERE id = 'a6666666-6666-6666-6666-666666666666'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "6"}, {"label": "B", "text": "10"}, {"label": "C", "text": "12"}, {"label": "D", "text": "16"}]'::jsonb, 'B', 'Do division first: 18 ÷ 3 = 6, then add 4 to get 10.', ARRAY['sat', 'math', 'algebra', 'order_of_operations'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('M033', 'A store buys pens for $2 each and sells them for $3.50 each. What is the profit per pen?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'algebra'), (SELECT id FROM skills WHERE id = 'a7777777-7777-7777-7777-777777777777'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "1.0"}, {"label": "B", "text": "1.5"}, {"label": "C", "text": "1.25"}, {"label": "D", "text": "2.0"}]'::jsonb, 'B', 'Profit is selling price minus cost: 3.50 - 2.00 = 1.50.', ARRAY['sat', 'math', 'algebra', 'word_problems'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('M034', 'If 4x - 1 = 15, what is x?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'algebra'), (SELECT id FROM skills WHERE id = '5b31574d-b72a-4b5d-ae15-81b144cff4ec'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "3"}, {"label": "B", "text": "4"}, {"label": "C", "text": "5"}, {"label": "D", "text": "6"}]'::jsonb, 'B', 'Add 1 to get 4x = 16, then divide by 4.', ARRAY['sat', 'math', 'algebra', 'linear_equations'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('M035', 'What is the simplified form of (2x)(3x^2)?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'advanced-math'), (SELECT id FROM skills WHERE id = 'b5555555-5555-5555-5555-555555555555'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "5x^3"}, {"label": "B", "text": "6x^3"}, {"label": "C", "text": "6x^2"}, {"label": "D", "text": "5x^2"}]'::jsonb, 'B', 'Multiply coefficients and add exponents: 2 × 3 = 6 and x^(1+2) = x^3.', ARRAY['sat', 'math', 'advanced_math', 'exponent_rules'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('M036', 'A class has 12 girls and 8 boys. What fraction of the class are boys?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'problem-solving-data'), (SELECT id FROM skills WHERE id = 'd4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "3/5"}, {"label": "B", "text": "2/5"}, {"label": "C", "text": "1/2"}, {"label": "D", "text": "1/4"}]'::jsonb, 'B', 'There are 8 boys out of 20 students total, which simplifies to 2/5.', ARRAY['sat', 'math', 'statistics', 'fractions'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('M037', 'If p = 2 and q = 6, what is p^2 + q?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'algebra'), (SELECT id FROM skills WHERE id = 'a4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "8"}, {"label": "B", "text": "10"}, {"label": "C", "text": "12"}, {"label": "D", "text": "14"}]'::jsonb, 'B', 'Compute 2^2 + 6 = 4 + 6 = 10.', ARRAY['sat', 'math', 'algebra', 'expression_evaluation'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('M038', 'A line has equation y = -2x + 9. What is the y-value when x = 0?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'algebra'), (SELECT id FROM skills WHERE id = '2bd9578b-1a5d-47d3-8ee3-ed8937992e7c'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "0"}, {"label": "B", "text": "9"}, {"label": "C", "text": "-2"}, {"label": "D", "text": "-9"}]'::jsonb, 'B', 'When x = 0, the y-intercept is 9.', ARRAY['sat', 'math', 'algebra', 'linear_functions'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('M039', 'If a square has side length 11, what is its perimeter?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'geometry-trigonometry'), (SELECT id FROM skills WHERE id = 'c1111111-1111-1111-1111-111111111111'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "22"}, {"label": "B", "text": "44"}, {"label": "C", "text": "33"}, {"label": "D", "text": "121"}]'::jsonb, 'B', 'Perimeter of a square is 4s: 4 × 11 = 44.', ARRAY['sat', 'math', 'geometry', 'perimeter'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status);

-- Writing Questions W001-W030
INSERT INTO question_bank (display_id, question_text, section, domain_id, skill_id, difficulty, question_format, choices, correct_answer, explanation, tags, gamemodes, source, status) VALUES
('W001', 'Choose the best revision: "The club met on Friday, and it discussed the plan in detail, which helped everyone understand the schedule."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'conventions'), (SELECT id FROM skills WHERE id = 'e1111111-1111-1111-1111-111111111111'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "The club met on Friday; and it discussed the plan in detail, which helped everyone understand the schedule."}, {"label": "B", "text": "The club met on Friday, and discussed the plan in detail which helped everyone understand the schedule."}, {"label": "C", "text": "The club met on Friday and discussed the plan in detail, which helped everyone understand the schedule."}, {"label": "D", "text": "The club met on Friday and it discussed the plan in detail, which helped everyone understand the schedule."}]'::jsonb, 'C', 'The sentence is clearer without the unnecessary comma after Friday, and the verbs should stay parallel.', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W002', 'Choose the best transition: "The trail was steep. ___, the hikers kept going because the view at the summit was worth it."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e3333333-3333-3333-3333-333333333333'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "For example"}, {"label": "B", "text": "Nevertheless"}, {"label": "C", "text": "Similarly"}, {"label": "D", "text": "Meanwhile"}]'::jsonb, 'B', 'The second sentence contrasts the difficulty with the hikers'' decision to continue, so ''Nevertheless'' fits best.', ARRAY['sat', 'reading_writing', 'usage'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W003', 'Choose the best revision: "Each of the students brought their own notebook to the workshop."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'expression-ideas'), (SELECT id FROM skills WHERE id = 'e2222222-2222-2222-2222-222222222222'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "Each of the students brought its own notebook to the workshop."}, {"label": "B", "text": "Each of the students brought their own notebooks to the workshop."}, {"label": "C", "text": "Each of the students bring his or her own notebook to the workshop."}, {"label": "D", "text": "Each of the students brought his or her own notebook to the workshop."}]'::jsonb, 'D', '''Each'' is singular, so the pronoun should also be singular and agree in number.', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W004', 'Choose the best revision: "The museum was crowded, the exhibit still felt quiet and reflective."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'conventions'), (SELECT id FROM skills WHERE id = 'e1111111-1111-1111-1111-111111111111'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "The museum was crowded, but the exhibit still felt quiet and reflective."}, {"label": "B", "text": "The museum was crowded; the exhibit, still felt quiet and reflective."}, {"label": "C", "text": "The museum was crowded and the exhibit still felt quiet and reflective."}, {"label": "D", "text": "The museum was crowded. The exhibit still felt quiet and reflective."}]'::jsonb, 'A', 'The sentence needs a conjunction that shows contrast between the crowded museum and the calm exhibit.', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W005', 'Choose the best revision: "The report was not only detailed but also it was useful."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e3333333-3333-3333-3333-333333333333'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "The report was not only detailed but also useful."}, {"label": "B", "text": "The report was not only detailed, but also it was useful."}, {"label": "C", "text": "The report was not only detailed but useful also it was."}, {"label": "D", "text": "The report was detailed, not only but also useful."}]'::jsonb, 'A', 'The two linked ideas should stay parallel: ''detailed'' and ''useful.''', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W006', 'Choose the best revision: "After running three miles, the finish line finally appeared."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'expression-ideas'), (SELECT id FROM skills WHERE id = 'e2222222-2222-2222-2222-222222222222'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "After running three miles, the runner finally saw the finish line."}, {"label": "B", "text": "After running three miles, the finish line finally saw the runner."}, {"label": "C", "text": "The finish line finally appeared after running three miles."}, {"label": "D", "text": "After running three miles, finally appeared the finish line."}]'::jsonb, 'A', 'As written, the sentence creates a confusing dangling modifier. The revised version clearly identifies who did the running.', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W007', 'Choose the best punctuation: "The project required patience ___ creativity ___ and teamwork."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'conventions'), (SELECT id FROM skills WHERE id = 'e1111111-1111-1111-1111-111111111111'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "patience creativity, and teamwork"}, {"label": "B", "text": "patience; creativity; and teamwork"}, {"label": "C", "text": "patience, creativity, and teamwork"}, {"label": "D", "text": "patience, creativity and teamwork"}]'::jsonb, 'C', 'A three-item list should use commas, including the serial comma before ''and.''', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W008', 'Choose the best revision: "The coach explained that the team would improve if it practiced, listened, and that it stayed focused."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e3333333-3333-3333-3333-333333333333'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "The coach explained that the team would improve if it practiced, listened, and stayed focused."}, {"label": "B", "text": "The coach explained that the team would improve if it practices, listened, and stayed focused."}, {"label": "C", "text": "The coach explained that the team would improve if it practiced, listened, and that staying focused."}, {"label": "D", "text": "The coach explained the team would improve if it practiced, listened, and it stayed focused."}]'::jsonb, 'A', 'The items in the list should be parallel: practiced, listened, and stayed focused.', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W009', 'Choose the best word to complete the sentence: "The scientist''s notes were so ___ that other researchers could repeat the experiment exactly."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'expression-ideas'), (SELECT id FROM skills WHERE id = 'e2222222-2222-2222-2222-222222222222'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "vague"}, {"label": "B", "text": "precise"}, {"label": "C", "text": "brief"}, {"label": "D", "text": "hesitant"}]'::jsonb, 'B', 'The ability to repeat the experiment exactly depends on careful and precise notes.', ARRAY['sat', 'reading_writing', 'usage'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status);

-- W010-W020
INSERT INTO question_bank (display_id, question_text, section, domain_id, skill_id, difficulty, question_format, choices, correct_answer, explanation, tags, gamemodes, source, status) VALUES
('W010', 'Choose the best revision: "Because the app was updated, the new features were easier to find, which pleased the users."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'conventions'), (SELECT id FROM skills WHERE id = 'e1111111-1111-1111-1111-111111111111'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "Because the app was updated, the new features were easier to find, and users were pleased."}, {"label": "B", "text": "Because the app was updated the new features were easier to find which pleased the users."}, {"label": "C", "text": "Because the app was updated, and the new features were easier to find, which pleased the users."}, {"label": "D", "text": "Because the app was updated, the new features were easier to find which pleased the users and."}]'::jsonb, 'A', 'The revised version keeps the causal idea clear and removes an awkward relative clause.', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W011', 'Choose the best revision: "The art teacher, along with her students, are preparing the display."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e3333333-3333-3333-3333-333333333333'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "The art teacher, along with her students, is preparing the display."}, {"label": "B", "text": "The art teacher, along with her students, were preparing the display."}, {"label": "C", "text": "The art teacher, along with her students, are prepare the display."}, {"label": "D", "text": "The art teacher, along with her students, is prepare the display."}]'::jsonb, 'A', 'The subject ''teacher'' is singular, so the verb should be singular too.', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W012', 'Choose the best transition: "The team had limited time. ___, it completed the presentation early."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'expression-ideas'), (SELECT id FROM skills WHERE id = 'e2222222-2222-2222-2222-222222222222'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "Therefore"}, {"label": "B", "text": "Otherwise"}, {"label": "C", "text": "Likewise"}, {"label": "D", "text": "Still"}]'::jsonb, 'D', 'The second sentence shows an unexpected result, so ''Still'' fits best.', ARRAY['sat', 'reading_writing', 'usage'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W013', 'Choose the best revision: "The proposal was approved because it was clear, and it had strong evidence, and it was concise."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'conventions'), (SELECT id FROM skills WHERE id = 'e1111111-1111-1111-1111-111111111111'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "The proposal was approved because it was clear and it had strong evidence and it was concise."}, {"label": "B", "text": "The proposal was approved because it was clear, it had strong evidence, and concise."}, {"label": "C", "text": "The proposal was approved because clear, strong evidence, and concise it was."}, {"label": "D", "text": "The proposal was approved because it was clear, supported by strong evidence, and concise."}]'::jsonb, 'D', 'This revision keeps the three qualities parallel and removes repetitive phrasing.', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W014', 'Choose the best punctuation: "The concert ___ which began at 7 p.m. ___ ended with a surprise encore."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e3333333-3333-3333-3333-333333333333'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "The concert, which began at 7 p.m., ended with a surprise encore."}, {"label": "B", "text": "The concert which began at 7 p.m., ended with a surprise encore."}, {"label": "C", "text": "The concert, which began at 7 p.m. ended with a surprise encore."}, {"label": "D", "text": "The concert which began at 7 p.m. ended with a surprise encore."}]'::jsonb, 'A', 'The nonessential clause should be set off with commas on both sides.', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W015', 'Choose the best revision: "The findings were important, they were not surprising."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'expression-ideas'), (SELECT id FROM skills WHERE id = 'e2222222-2222-2222-2222-222222222222'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "The findings were important they were not surprising."}, {"label": "B", "text": "The findings were important, but they were not surprising."}, {"label": "C", "text": "The findings were important; because they were not surprising."}, {"label": "D", "text": "The findings were important, and because they were not surprising."}]'::jsonb, 'B', 'A coordinating conjunction is needed to join the two independent clauses.', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W016', 'Choose the best revision: "For the final draft, the writer removed unnecessary words in order to make it more concise and clearer."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'conventions'), (SELECT id FROM skills WHERE id = 'e1111111-1111-1111-1111-111111111111'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "For the final draft, the writer removed unnecessary words to make it more concise and clear."}, {"label": "B", "text": "For the final draft, the writer removed unnecessary words in order to make it more concise and clearerly."}, {"label": "C", "text": "For the final draft, the writer removed unnecessary words to make it more concise and more clearer."}, {"label": "D", "text": "For the final draft, the writer removed unnecessary words, making it more concise and clearer."}]'::jsonb, 'A', 'The adjectives should be parallel, so ''clear'' matches ''concise'' better than ''clearer.''', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W017', 'Choose the best revision: "Neither the principal nor the teachers was ready for the announcement."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e3333333-3333-3333-3333-333333333333'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "Neither the principal nor the teachers was ready for the announcement."}, {"label": "B", "text": "Neither the principal nor the teachers is ready for the announcement."}, {"label": "C", "text": "Neither the principal nor the teachers be ready for the announcement."}, {"label": "D", "text": "Neither the principal nor the teachers were ready for the announcement."}]'::jsonb, 'D', 'With ''nor,'' the verb agrees with the nearer subject, which is plural ''teachers.''', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W018', 'Choose the best transition: "The experiment failed three times. ___, the team learned which variable mattered most."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'expression-ideas'), (SELECT id FROM skills WHERE id = 'e2222222-2222-2222-2222-222222222222'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "Ultimately"}, {"label": "B", "text": "Consequently"}, {"label": "C", "text": "Meanwhile"}, {"label": "D", "text": "In contrast"}]'::jsonb, 'A', 'The final result is a conclusion from the repeated failures, so ''Ultimately'' fits best.', ARRAY['sat', 'reading_writing', 'usage'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W019', 'Choose the best revision: "The cyclist wore a helmet, gloves, and he had reflective lights."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'conventions'), (SELECT id FROM skills WHERE id = 'e1111111-1111-1111-1111-111111111111'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "The cyclist wore a helmet, gloves, and reflective lights."}, {"label": "B", "text": "The cyclist wore a helmet, gloves, and had reflective lights."}, {"label": "C", "text": "The cyclist wore a helmet, gloves, and he was reflective lights."}, {"label": "D", "text": "The cyclist wore a helmet gloves, and reflective lights."}]'::jsonb, 'A', 'This keeps the items in a parallel list and removes the unnecessary pronoun.', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status);

-- W020-W030
INSERT INTO question_bank (display_id, question_text, section, domain_id, skill_id, difficulty, question_format, choices, correct_answer, explanation, tags, gamemodes, source, status) VALUES
('W020', 'Choose the best word to complete the sentence: "The old bridge was built from durable materials, so it remained ___ even after many storms."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e3333333-3333-3333-3333-333333333333'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "fragile"}, {"label": "B", "text": "sturdy"}, {"label": "C", "text": "temporary"}, {"label": "D", "text": "uneven"}]'::jsonb, 'B', 'A bridge that survives many storms would be sturdy.', ARRAY['sat', 'reading_writing', 'usage'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W021', 'Choose the best revision: "The students studied hard; therefore, they were tired, but they finished the project."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'expression-ideas'), (SELECT id FROM skills WHERE id = 'e2222222-2222-2222-2222-222222222222'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "The students studied hard; therefore, they were tired, but they finished the project."}, {"label": "B", "text": "The students studied hard therefore, they were tired but they finished the project."}, {"label": "C", "text": "The students studied hard; therefore they were tired, but, they finished the project."}, {"label": "D", "text": "The students studied hard, therefore, they were tired; but they finished the project."}]'::jsonb, 'A', 'The original punctuation is already correct; the best choice preserves the semicolon and comma structure.', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W022', 'Choose the best revision: "The author, who lives in Boston, write essays about city life."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'conventions'), (SELECT id FROM skills WHERE id = 'e1111111-1111-1111-1111-111111111111'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "The author, who lives in Boston, write essay about city life."}, {"label": "B", "text": "The author, who live in Boston, writes essays about city life."}, {"label": "C", "text": "The author, who lives in Boston, writing essays about city life."}, {"label": "D", "text": "The author, who lives in Boston, writes essays about city life."}]'::jsonb, 'D', 'The singular subject ''author'' needs the singular verb ''writes.''', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W023', 'Choose the best transition: "The instructions were confusing. ___, the students completed the task by working together."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e3333333-3333-3333-3333-333333333333'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "Nevertheless"}, {"label": "B", "text": "In fact"}, {"label": "C", "text": "Similarly"}, {"label": "D", "text": "For instance"}]'::jsonb, 'A', 'The second sentence shows contrast with the first, so ''Nevertheless'' works best.', ARRAY['sat', 'reading_writing', 'usage'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W024', 'Choose the best revision: "The new policy, which was introduced in January, have already changed the schedule."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'expression-ideas'), (SELECT id FROM skills WHERE id = 'e2222222-2222-2222-2222-222222222222'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "The new policy, which was introduced in January, have already change the schedule."}, {"label": "B", "text": "The new policy, which was introduced in January, has already changed the schedule."}, {"label": "C", "text": "The new policy, which were introduced in January, has already changed the schedule."}, {"label": "D", "text": "The new policy which was introduced in January, have already changed the schedule."}]'::jsonb, 'B', 'The subject ''policy'' is singular, so the verb should be ''has.''', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W025', 'Choose the best revision: "The author wanted to show that courage is important, that honesty matters, and to be kind."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'conventions'), (SELECT id FROM skills WHERE id = 'e1111111-1111-1111-1111-111111111111'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "The author wanted to show that courage is important, that honesty matters, and that kindness matters too."}, {"label": "B", "text": "The author wanted to show courage is important, that honesty matters, and to be kind."}, {"label": "C", "text": "The author wanted to show that courage is important, honesty matters, and to be kind."}, {"label": "D", "text": "The author wanted to show that courage is important, honesty matters, and kindness."}]'::jsonb, 'A', 'The list should be parallel and each idea should have the same grammatical structure.', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W026', 'Choose the best punctuation: "After the meeting ___ the manager sent a summary email."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e3333333-3333-3333-3333-333333333333'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "After the meeting; the manager sent a summary email."}, {"label": "B", "text": "After the meeting, the manager sent a summary email."}, {"label": "C", "text": "After the meeting the manager, sent a summary email."}, {"label": "D", "text": "After the meeting: the manager sent a summary email."}]'::jsonb, 'B', 'A comma is the correct punctuation after the introductory phrase.', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W027', 'Choose the best revision: "The device was expensive, but it was worth every penny because of its reliability and because it lasted long."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'expression-ideas'), (SELECT id FROM skills WHERE id = 'e2222222-2222-2222-2222-222222222222'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "The device was expensive, but it was worth every penny because its reliability and because it lasted long."}, {"label": "B", "text": "The device was expensive, but it was worth every penny because of reliable and because it lasted long."}, {"label": "C", "text": "The device was expensive, but it was worth every penny because of its reliability and long life."}, {"label": "D", "text": "The device was expensive, but it was worth every penny because of its reliability and because long life."}]'::jsonb, 'C', 'This revision removes redundancy and keeps the phrase smooth and concise.', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W028', 'Choose the best word to complete the sentence: "The coach used a calm voice to ___ the players before the game."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'conventions'), (SELECT id FROM skills WHERE id = 'e1111111-1111-1111-1111-111111111111'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "frustrate"}, {"label": "B", "text": "confuse"}, {"label": "C", "text": "delay"}, {"label": "D", "text": "reassure"}]'::jsonb, 'D', 'A calm voice would reassure the players, not frustrate or confuse them.', ARRAY['sat', 'reading_writing', 'usage'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status),
('W029', 'Choose the best revision: "The project succeeded because of teamwork, planning, and the fact that everyone helped each other."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e3333333-3333-3333-3333-333333333333'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "The project succeeded because of teamwork, planning, and because everyone helped each other."}, {"label": "B", "text": "The project succeeded because of teamwork, planning, and mutual support."}, {"label": "C", "text": "The project succeeded because of teamwork, planning, and that everyone helped each other."}, {"label": "D", "text": "The project succeeded because teamwork, planning, and the fact everyone helping."}]'::jsonb, 'B', 'The revision avoids redundancy and keeps the list concise.', ARRAY['sat', 'reading_writing', 'grammar'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status);

-- W030
INSERT INTO question_bank (display_id, question_text, section, domain_id, skill_id, difficulty, question_format, choices, correct_answer, explanation, tags, gamemodes, source, status) VALUES
('W030', 'Choose the best revision: "The librarian helped the students find books, magazines, and she also showed them how to use the catalog."', 'writing'::sat_section, (SELECT id FROM domains WHERE slug = 'conventions'), (SELECT id FROM skills WHERE id = '79404713-9348-42dd-b1b7-64af41763dd6'::uuid), 'easy'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "The librarian helped the students find books and magazines and also showed them how to use the catalog."}, {"label": "B", "text": "The librarian helped the students find books, magazines, and also she showed them how to use the catalog."}, {"label": "C", "text": "The librarian helped the students find books and magazines, and she also showed them how to use the catalog."}, {"label": "D", "text": "The librarian helped the students find books, magazines, and showed them how to use the catalog also."}]'::jsonb, 'A', 'The revision removes the awkward pronoun and keeps the list smooth.', ARRAY['sat', 'reading_writing', 'sentence_structure'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status);

-- Reading Comprehension Questions R001-R020 (Passage-based)
INSERT INTO question_bank (display_id, question_text, section, domain_id, skill_id, difficulty, question_format, choices, correct_answer, explanation, tags, gamemodes, source, status, passage, passage_id) VALUES
-- R001-R002 share passage R1
('R001', 'What is the main idea of the passage?', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'information-and-ideas'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "The students wanted to reopen the community pool as quickly as possible."}, {"label": "B", "text": "The park was already in perfect condition before the cleanup began."}, {"label": "C", "text": "A small student project became a community effort that brought people together."}, {"label": "D", "text": "The neighbors discouraged the students from working outside."}]'::jsonb, 'C', 'The passage focuses on how the cleanup grew into a larger community tradition.', ARRAY['sat', 'reading', 'r1', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'When the old community pool was closed for repairs, a group of students started a weekend cleanup project at a nearby park. At first, they expected to spend one afternoon collecting trash and trimming weeds. Instead, neighbors began joining them with gloves, rakes, and coolers of water. By the end of the month, the project had grown into a small community tradition. The students realized that their original goal was only part of the result; the larger change was that people who rarely spoke to one another had started working side by side.', 'R1'),
('R002', 'Which detail best supports the idea that the project grew beyond the students'' original plan?', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "The students expected to spend one afternoon collecting trash and trimming weeds."}, {"label": "B", "text": "Neighbors began joining them with gloves, rakes, and coolers of water."}, {"label": "C", "text": "The old community pool was closed for repairs."}, {"label": "D", "text": "The students worked at a nearby park."}]'::jsonb, 'B', 'This detail shows that other people joined and expanded the project.', ARRAY['sat', 'reading', 'r1', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'When the old community pool was closed for repairs, a group of students started a weekend cleanup project at a nearby park. At first, they expected to spend one afternoon collecting trash and trimming weeds. Instead, neighbors began joining them with gloves, rakes, and coolers of water. By the end of the month, the project had grown into a small community tradition. The students realized that their original goal was only part of the result; the larger change was that people who rarely spoke to one another had started working side by side.', 'R1'),

-- R003-R004 share passage R2
('R003', 'What is the central purpose of the passage?', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'information-and-ideas'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "To describe a library project that repairs books and extends their use."}, {"label": "B", "text": "To explain why the library should replace all old books with new ones."}, {"label": "C", "text": "To argue that libraries should stop using volunteers."}, {"label": "D", "text": "To describe a contest between different city libraries."}]'::jsonb, 'A', 'The passage explains how the repair shelf works and why it matters.', ARRAY['sat', 'reading', 'r2', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'A city library created a ''repair shelf'' for damaged books that could still be saved. Volunteers learned how to mend torn pages, replace loose covers, and label books for quick return to circulation. The project cost very little because it relied on donated materials and training from retired librarians. Some people assumed the shelf would fill slowly, but within six months, it had helped thousands of books return to readers. The library staff said the biggest benefit was not only saving money, but also showing visitors that care and patience could keep useful things in service longer.', 'R2'),
('R004', 'The word ''circulation'' most nearly means', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'medium'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "being stored in a museum forever."}, {"label": "B", "text": "being available for people to borrow."}, {"label": "C", "text": "being moved to a different city."}, {"label": "D", "text": "being checked for spelling mistakes."}]'::jsonb, 'B', 'In a library, circulation means books are available to be borrowed.', ARRAY['sat', 'reading', 'r2', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'A city library created a ''repair shelf'' for damaged books that could still be saved. Volunteers learned how to mend torn pages, replace loose covers, and label books for quick return to circulation. The project cost very little because it relied on donated materials and training from retired librarians. Some people assumed the shelf would fill slowly, but within six months, it had helped thousands of books return to readers. The library staff said the biggest benefit was not only saving money, but also showing visitors that care and patience could keep useful things in service longer.', 'R2'),

-- R005-R006 share passage R3
('R005', 'Which statement best expresses the passage''s main point?', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'information-and-ideas'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "The town should stop hosting the lantern walk because it costs too much."}, {"label": "B", "text": "The artists care only about painting and not about the event itself."}, {"label": "C", "text": "A small event became a meaningful tradition that helps people value their town''s history."}, {"label": "D", "text": "The river path is dangerous and should be closed."}]'::jsonb, 'C', 'The passage emphasizes tradition, community, and historical memory.', ARRAY['sat', 'reading', 'r3', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'Every spring, a small town hosts a lantern walk along its river path. Local artists paint paper lanterns with scenes from the town''s history, and families carry them after sunset. The event began as a simple school fundraiser, but it now draws visitors from nearby towns. Organizers say the walk matters because it gives people a reason to look carefully at the place where they live. The lanterns are temporary, but the stories attached to them help residents remember how the town changed over time.', 'R3'),
('R006', 'Why do the organizers think the lantern walk matters?', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "It encourages people to notice and appreciate their town."}, {"label": "B", "text": "It proves that lanterns are more useful than candles."}, {"label": "C", "text": "It helps the town avoid using the river path."}, {"label": "D", "text": "It replaces all other festivals in nearby towns."}]'::jsonb, 'A', 'The passage says it gives people a reason to look carefully at where they live.', ARRAY['sat', 'reading', 'r3', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'Every spring, a small town hosts a lantern walk along its river path. Local artists paint paper lanterns with scenes from the town''s history, and families carry them after sunset. The event began as a simple school fundraiser, but it now draws visitors from nearby towns. Organizers say the walk matters because it gives people a reason to look carefully at the place where they live. The lanterns are temporary, but the stories attached to them help residents remember how the town changed over time.', 'R3');

-- R007-R020
INSERT INTO question_bank (display_id, question_text, section, domain_id, skill_id, difficulty, question_format, choices, correct_answer, explanation, tags, gamemodes, source, status, passage, passage_id) VALUES
-- R007-R008 share passage R4
('R007', 'What does the teacher''s comment suggest?', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'information-and-ideas'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "Researchers should look at results over time, not just the first outcome."}, {"label": "B", "text": "The seed experiment was too simple to matter."}, {"label": "C", "text": "The students should only use compost in every experiment."}, {"label": "D", "text": "The first sprouts were the only important data."}]'::jsonb, 'A', 'The teacher emphasizes that later results can change the interpretation.', ARRAY['sat', 'reading', 'r4', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'In a biology class, students tested how quickly seeds sprouted in different soil mixtures. One group used soil with extra sand, another used soil rich in compost, and a third used standard potting soil. The students expected the compost mix to win immediately, but the first sprouts appeared in the potting soil. By the end of the week, however, the compost mix produced the healthiest seedlings. The teacher said the experiment showed that first results do not always tell the whole story.', 'R4'),
('R008', 'Which detail best supports the idea that the compost mix was ultimately strongest?', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'medium'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "By the end of the week, the compost mix produced the healthiest seedlings."}, {"label": "B", "text": "The first sprouts appeared in the potting soil."}, {"label": "C", "text": "One group used soil with extra sand."}, {"label": "D", "text": "The teacher ran the experiment in biology class."}]'::jsonb, 'A', 'This directly states the final result.', ARRAY['sat', 'reading', 'r4', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'In a biology class, students tested how quickly seeds sprouted in different soil mixtures. One group used soil with extra sand, another used soil rich in compost, and a third used standard potting soil. The students expected the compost mix to win immediately, but the first sprouts appeared in the potting soil. By the end of the week, however, the compost mix produced the healthiest seedlings. The teacher said the experiment showed that first results do not always tell the whole story.', 'R4'),

-- R009-R010 share passage R5
('R009', 'What is the teacher''s main idea?', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'information-and-ideas'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "Practice should always be short and easy."}, {"label": "B", "text": "Students improve when they practice the hardest parts first."}, {"label": "C", "text": "Music students should avoid difficult songs."}, {"label": "D", "text": "Teachers should remove all discomfort from learning."}]'::jsonb, 'B', 'The teacher believes hard practice helps students improve.', ARRAY['sat', 'reading', 'r5', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'A music teacher noticed that several students practiced only the easiest parts of their songs. To change that habit, she asked them to begin every session with the section they feared most. At first, the students complained that this made practice less fun. After a few weeks, though, they reported feeling more confident because difficult passages no longer seemed mysterious. The teacher did not argue that practice should be painless; instead, she argued that discomfort could be useful when it led to improvement.', 'R5'),
('R010', 'Which phrase best shows the students'' change in attitude?', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "they complained that this made practice less fun"}, {"label": "B", "text": "she asked them to begin every session"}, {"label": "C", "text": "the section they feared most"}, {"label": "D", "text": "they reported feeling more confident"}]'::jsonb, 'D', 'This phrase shows the students became more confident over time.', ARRAY['sat', 'reading', 'r5', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'A music teacher noticed that several students practiced only the easiest parts of their songs. To change that habit, she asked them to begin every session with the section they feared most. At first, the students complained that this made practice less fun. After a few weeks, though, they reported feeling more confident because difficult passages no longer seemed mysterious. The teacher did not argue that practice should be painless; instead, she argued that discomfort could be useful when it led to improvement.', 'R5'),

-- R011-R012 share passage R6
('R011', 'The passage suggests that the bench', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'information-and-ideas'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "was never used by anyone."}, {"label": "B", "text": "was the most expensive part of the garden."}, {"label": "C", "text": "was placed there to block the path."}, {"label": "D", "text": "helped turn the garden into a more social space."}]'::jsonb, 'D', 'The bench became a gathering spot and changed the garden''s atmosphere.', ARRAY['sat', 'reading', 'r6', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'A neighborhood garden added a bench made from recycled wood. Some residents thought the bench was only decorative, but others soon began using it as a place to talk while waiting for volunteers to water plants. The bench became a quiet gathering spot, especially on warm evenings. Its purpose changed over time: what began as a simple object helped make the garden feel more like a shared room than a public plot of land.', 'R6'),
('R012', 'The word ''shared'' in the passage most nearly means', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'medium'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "painted in one color."}, {"label": "B", "text": "locked in a storage room."}, {"label": "C", "text": "used together by many people."}, {"label": "D", "text": "cut into several pieces."}]'::jsonb, 'C', 'The garden felt like a place used and enjoyed by many people.', ARRAY['sat', 'reading', 'r6', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'A neighborhood garden added a bench made from recycled wood. Some residents thought the bench was only decorative, but others soon began using it as a place to talk while waiting for volunteers to water plants. The bench became a quiet gathering spot, especially on warm evenings. Its purpose changed over time: what began as a simple object helped make the garden feel more like a shared room than a public plot of land.', 'R6'),

-- R013-R014 share passage R7
('R013', 'What is the main purpose of the checklist?', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'information-and-ideas'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "To replace every bike repair shop."}, {"label": "B", "text": "To teach riders how to race faster."}, {"label": "C", "text": "To make bike rides longer."}, {"label": "D", "text": "To make bike safety faster and easier to remember."}]'::jsonb, 'D', 'The checklist is short and helps riders remember basic safety steps.', ARRAY['sat', 'reading', 'r7', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'An engineer studying bike safety noticed that riders often overlooked small details, like loose straps and worn tires, before a trip. She designed a short checklist that could be completed in less than a minute. Riders who used the checklist reported fewer mid-ride problems and felt more prepared before leaving home. The engineer said the best safety tools are often the ones people can use so easily that they become part of a routine.', 'R7'),
('R014', 'Which detail supports the claim that the checklist was useful?', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "The checklist could be completed in less than a minute."}, {"label": "B", "text": "The engineer studied bike safety."}, {"label": "C", "text": "Riders often overlooked small details."}, {"label": "D", "text": "Riders who used the checklist reported fewer mid-ride problems."}]'::jsonb, 'D', 'Fewer mid-ride problems is direct evidence of usefulness.', ARRAY['sat', 'reading', 'r7', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'An engineer studying bike safety noticed that riders often overlooked small details, like loose straps and worn tires, before a trip. She designed a short checklist that could be completed in less than a minute. Riders who used the checklist reported fewer mid-ride problems and felt more prepared before leaving home. The engineer said the best safety tools are often the ones people can use so easily that they become part of a routine.', 'R7'),

-- R015-R016 share passage R8
('R015', 'Why do scientists call reefs networks?', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'information-and-ideas'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "Because reefs are made of stone and metal."}, {"label": "B", "text": "Because each animal lives completely alone."}, {"label": "C", "text": "Because the organisms in a reef depend on one another."}, {"label": "D", "text": "Because reefs do not change over time."}]'::jsonb, 'C', 'The passage emphasizes interdependence among organisms.', ARRAY['sat', 'reading', 'r8', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'At first glance, a coral reef may seem like a stone wall under the sea. In reality, it is alive with organisms that depend on one another. Tiny animals build the reef, fish hide in its crevices, and algae provide energy that helps many species survive. When any part of the system weakens, the entire reef becomes less stable. That is why scientists describe reefs as networks rather than as collections of isolated parts.', 'R8'),
('R016', 'The phrase ''less stable'' most nearly means', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'medium'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "more colorful and bright."}, {"label": "B", "text": "more expensive to study."}, {"label": "C", "text": "more likely to be disrupted or damaged."}, {"label": "D", "text": "more hidden from view."}]'::jsonb, 'C', 'If one part weakens, the reef can be disrupted.', ARRAY['sat', 'reading', 'r8', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'At first glance, a coral reef may seem like a stone wall under the sea. In reality, it is alive with organisms that depend on one another. Tiny animals build the reef, fish hide in its crevices, and algae provide energy that helps many species survive. When any part of the system weakens, the entire reef becomes less stable. That is why scientists describe reefs as networks rather than as collections of isolated parts.', 'R8'),

-- R017-R018 share passage R9
('R017', 'Which choice best states the main idea?', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'information-and-ideas'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "School newspapers should only publish fiction reviews."}, {"label": "B", "text": "Good books often inspire new questions rather than just giving facts."}, {"label": "C", "text": "Students dislike books that are difficult to understand."}, {"label": "D", "text": "Astronomy and history are the same subject."}]'::jsonb, 'B', 'The passage argues that strong books make readers more curious.', ARRAY['sat', 'reading', 'r9', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'A school newspaper asked students to write about a book that changed the way they saw a subject in class. Many responses described the same feeling: the best books did not simply provide facts; they changed the reader''s questions. A student who wrote about astronomy said the book helped her notice how much she did not know. Another student said a history book made him curious about the people behind the dates. The editors concluded that reading can matter most when it increases curiosity rather than ending it.', 'R9'),
('R018', 'What does the astronomy student say the book helped her do?', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "Memorize every fact in the chapter."}, {"label": "B", "text": "Notice how much she did not know."}, {"label": "C", "text": "Stop caring about astronomy."}, {"label": "D", "text": "Avoid asking questions."}]'::jsonb, 'B', 'The student realized the book revealed gaps in her knowledge.', ARRAY['sat', 'reading', 'r9', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'A school newspaper asked students to write about a book that changed the way they saw a subject in class. Many responses described the same feeling: the best books did not simply provide facts; they changed the reader''s questions. A student who wrote about astronomy said the book helped her notice how much she did not know. Another student said a history book made him curious about the people behind the dates. The editors concluded that reading can matter most when it increases curiosity rather than ending it.', 'R9'),

-- R019-R020 share passage R10
('R019', 'What is the passage mainly about?', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'information-and-ideas'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'easy'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "The train station should be removed from the neighborhood."}, {"label": "B", "text": "Public art can improve both safety and the feeling of a place."}, {"label": "C", "text": "Crosswalks are best when they are invisible."}, {"label": "D", "text": "Drivers always ignore colorful street designs."}]'::jsonb, 'B', 'The passage connects art with safety and community identity.', ARRAY['sat', 'reading', 'r10', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'A public art project painted large crosswalks near a train station. The bright shapes made the street easier to notice, and drivers slowed down more often as they approached the intersection. Residents also said the art made a familiar place feel less ordinary. Some cities treat public art as decoration, but the organizers of this project saw it as a tool that could improve both safety and civic pride.', 'R10'),
('R020', 'Which detail best supports the idea that the art improved safety?', 'reading'::sat_section, (SELECT id FROM domains WHERE slug = 'craft-and-structure'), (SELECT id FROM skills WHERE id = 'e4444444-4444-4444-4444-444444444444'::uuid), 'medium'::difficulty_level, 'passage_based'::question_format, '[{"label": "A", "text": "Drivers slowed down more often as they approached the intersection."}, {"label": "B", "text": "Residents said the place felt less ordinary."}, {"label": "C", "text": "The crosswalks were near a train station."}, {"label": "D", "text": "The shapes were bright."}]'::jsonb, 'A', 'Slowing down suggests safer driving behavior.', ARRAY['sat', 'reading', 'r10', 'comprehension'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, 'A public art project painted large crosswalks near a train station. The bright shapes made the street easier to notice, and drivers slowed down more often as they approached the intersection. Residents also said the art made a familiar place feel less ordinary. Some cities treat public art as decoration, but the organizers of this project saw it as a tool that could improve both safety and civic pride.', 'R10');

-- Visual/Data Analysis Questions C001-C011
INSERT INTO question_bank (display_id, question_text, section, domain_id, skill_id, difficulty, question_format, choices, correct_answer, explanation, tags, gamemodes, source, status, visual_spec, visual_data) VALUES
('C001', 'The table shows the number of practice questions completed by four students in one week. Which student completed the most questions?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'problem-solving-data'), (SELECT id FROM skills WHERE id = 'd5555555-5555-5555-5555-555555555555'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "Ava"}, {"label": "B", "text": "Ben"}, {"label": "C", "text": "Mina"}, {"label": "D", "text": "Zane"}]'::jsonb, 'C', 'Mina completed 48 questions, which is the highest value in the table.', ARRAY['sat', 'math', 'data_analysis', 'table'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, '{"type": "table", "bolt_instruction": "Create a clean, professional SAT-style visual for this item. Keep it simple, high-contrast, and easy to read. Use the data/context provided in the record."}'::jsonb, '{"Ava": 42, "Ben": 35, "Mina": 48, "Zane": 40}'::jsonb),
('C002', 'A tutoring app tracked time spent on Math review across four days. On which day did the student study the longest?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'problem-solving-data'), (SELECT id FROM skills WHERE id = 'd5555555-5555-5555-5555-555555555555'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "Monday"}, {"label": "B", "text": "Tuesday"}, {"label": "C", "text": "Wednesday"}, {"label": "D", "text": "Thursday"}]'::jsonb, 'D', 'Thursday has the greatest number of minutes: 50.', ARRAY['sat', 'math', 'data_analysis', 'table'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, '{"type": "table", "bolt_instruction": "Create a clean, professional SAT-style visual for this item. Keep it simple, high-contrast, and easy to read."}'::jsonb, '{"Monday": 25, "Tuesday": 40, "Wednesday": 35, "Thursday": 50}'::jsonb),
('C003', 'The bar chart values below show the number of questions answered correctly in each section. Which section had the lowest score?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'problem-solving-data'), (SELECT id FROM skills WHERE id = 'd5555555-5555-5555-5555-555555555555'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "Math"}, {"label": "B", "text": "Writing"}, {"label": "C", "text": "Reading"}, {"label": "D", "text": "Science"}]'::jsonb, 'C', 'Reading has 14, the smallest value.', ARRAY['sat', 'math', 'data_analysis', 'bar_chart'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, '{"type": "bar_chart", "bolt_instruction": "Create a clean, professional SAT-style visual for this item. Keep it simple, high-contrast, and easy to read."}'::jsonb, '{"Math": 18, "Reading": 14, "Writing": 16, "Science": 20}'::jsonb),
('C004', 'A line graph shows weekly scores of 62, 68, 70, and 76. What is the total increase from the first week to the last week?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'problem-solving-data'), (SELECT id FROM skills WHERE id = 'd5555555-5555-5555-5555-555555555555'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "8"}, {"label": "B", "text": "10"}, {"label": "C", "text": "12"}, {"label": "D", "text": "14"}]'::jsonb, 'D', '76 - 62 = 14.', ARRAY['sat', 'math', 'data_analysis', 'line_graph'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, '{"type": "line_graph", "bolt_instruction": "Create a clean, professional SAT-style visual for this item. Keep it simple, high-contrast, and easy to read."}'::jsonb, '{"Week 1": 62, "Week 2": 68, "Week 3": 70, "Week 4": 76}'::jsonb),
('C005', 'A table shows SAT practice accuracy by topic. Which topic improved the most from Round 1 to Round 2?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'problem-solving-data'), (SELECT id FROM skills WHERE id = 'd5555555-5555-5555-5555-555555555555'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "Algebra"}, {"label": "B", "text": "Geometry"}, {"label": "C", "text": "Grammar"}, {"label": "D", "text": "Reading"}]'::jsonb, 'C', 'Grammar improved by 15 points, the largest increase.', ARRAY['sat', 'math', 'data_analysis', 'comparison_table'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, '{"type": "comparison_table", "bolt_instruction": "Create a clean, professional SAT-style visual for this item. Keep it simple, high-contrast, and easy to read."}'::jsonb, '{"Algebra": [45, 60], "Geometry": [50, 56], "Grammar": [40, 55], "Reading": [52, 58]}'::jsonb),
('C006', 'A simple coordinate grid shows points A(1,2), B(3,6), and C(5,10). Which statement is true?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'problem-solving-data'), (SELECT id FROM skills WHERE id = 'd5555555-5555-5555-5555-555555555555'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "The points lie on a line with slope 2."}, {"label": "B", "text": "The points form a horizontal line."}, {"label": "C", "text": "The points have no relationship."}, {"label": "D", "text": "The slope is 1/2."}]'::jsonb, 'A', 'Each time x increases by 2, y increases by 4, so the slope is 4/2 = 2.', ARRAY['sat', 'math', 'data_analysis', 'coordinate_grid'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, '{"type": "coordinate_grid", "bolt_instruction": "Create a clean, professional SAT-style visual for this item. Keep it simple, high-contrast, and easy to read."}'::jsonb, '{"A": [1, 2], "B": [3, 6], "C": [5, 10]}'::jsonb),
('C007', 'The diagram shows a rectangle split into 3 equal columns and 2 equal rows. If the whole rectangle has area 30 square units, what is the area of one small section?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'problem-solving-data'), (SELECT id FROM skills WHERE id = 'd5555555-5555-5555-5555-555555555555'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "5"}, {"label": "B", "text": "4"}, {"label": "C", "text": "6"}, {"label": "D", "text": "10"}]'::jsonb, 'A', 'The rectangle has 6 equal parts, so 30 ÷ 6 = 5.', ARRAY['sat', 'math', 'data_analysis', 'diagram'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, '{"type": "diagram", "bolt_instruction": "Create a clean, professional SAT-style visual for this item. Keep it simple, high-contrast, and easy to read."}'::jsonb, '{"columns": 3, "rows": 2, "total_area": 30}'::jsonb),
('C008', 'A chart shows that a student answered 12 questions correctly out of 15 on Monday and 18 out of 24 on Tuesday. On which day was the accuracy higher?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'problem-solving-data'), (SELECT id FROM skills WHERE id = 'd5555555-5555-5555-5555-555555555555'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "Tuesday"}, {"label": "B", "text": "They were equal"}, {"label": "C", "text": "Neither day"}, {"label": "D", "text": "Monday"}]'::jsonb, 'D', 'Monday accuracy is 12/15 = 80%, while Tuesday is 18/24 = 75%.', ARRAY['sat', 'math', 'data_analysis', 'fraction_chart'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, '{"type": "fraction_chart", "bolt_instruction": "Create a clean, professional SAT-style visual for this item. Keep it simple, high-contrast, and easy to read."}'::jsonb, '{"Monday": [12, 15], "Tuesday": [18, 24]}'::jsonb),
('C009', 'The table below gives the number of users who logged in each day. What is the average number of users per day?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'problem-solving-data'), (SELECT id FROM skills WHERE id = 'd5555555-5555-5555-5555-555555555555'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "120"}, {"label": "B", "text": "130"}, {"label": "C", "text": "135"}, {"label": "D", "text": "150"}]'::jsonb, 'B', 'Add 120 + 140 + 100 + 160 = 520, then divide by 4 to get 130.', ARRAY['sat', 'math', 'data_analysis', 'table'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, '{"type": "table", "bolt_instruction": "Create a clean, professional SAT-style visual for this item. Keep it simple, high-contrast, and easy to read."}'::jsonb, '{"Mon": 120, "Tue": 140, "Wed": 100, "Thu": 160}'::jsonb),
('C010', 'A gauge chart shows a study streak rising from 3 days to 11 days. By how many days did the streak increase?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'problem-solving-data'), (SELECT id FROM skills WHERE id = 'd5555555-5555-5555-5555-555555555555'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "7"}, {"label": "B", "text": "9"}, {"label": "C", "text": "8"}, {"label": "D", "text": "11"}]'::jsonb, 'C', '11 - 3 = 8.', ARRAY['sat', 'math', 'data_analysis', 'gauge_chart'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, '{"type": "gauge_chart", "bolt_instruction": "Create a clean, professional SAT-style visual for this item. Keep it simple, high-contrast, and easy to read."}'::jsonb, '{"start": 3, "end": 11}'::jsonb),
('C011', 'A scatterplot shows that as study time increases, practice accuracy generally increases too. What kind of relationship is shown?', 'math'::sat_section, (SELECT id FROM domains WHERE slug = 'problem-solving-data'), (SELECT id FROM skills WHERE id = 'd5555555-5555-5555-5555-555555555555'::uuid), 'medium'::difficulty_level, 'multiple_choice'::question_format, '[{"label": "A", "text": "negative correlation"}, {"label": "B", "text": "positive correlation"}, {"label": "C", "text": "no correlation"}, {"label": "D", "text": "random correlation"}]'::jsonb, 'B', 'When both variables rise together, that is a positive correlation.', ARRAY['sat', 'math', 'data_analysis', 'scatterplot'], ARRAY['Study', 'Practice', 'Review', 'Challenge'], 'official'::question_source, 'published'::question_bank_status, '{"type": "scatterplot", "bolt_instruction": "Create a clean, professional SAT-style visual for this item. Keep it simple, high-contrast, and easy to read."}'::jsonb, '{"trend": "upward"}'::jsonb);